    15→// Based on github.com/grpc-ecosystem/go-grpc-middleware/retry, but modified to support the more
    16→// fine grained error checking required by write-at-most-once retry semantics of etcd.
    17→
    18→package clientv3
    19→
    20→import (
    21→	"context"
    22→	"errors"
    23→	"io"
    24→	"sync"
    25→	"time"
