    37→// unaryClientInterceptor returns a new retrying unary client interceptor.
    38→//
    39→// The default configuration of the interceptor is to not retry *at all*. This behaviour can be
    40→// changed through options (e.g. WithMax) on creation of the interceptor or on call (through grpc.CallOptions).
    41→func (c *Client) unaryClientInterceptor(optFuncs ...retryOption) grpc.UnaryClientInterceptor {
    42→	intOpts := reuseOrNewWithCallOptions(defaultOptions, optFuncs)
    43→	return func(ctx context.Context, method string, req, reply any, cc *grpc.ClientConn, invoker grpc.UnaryInvoker, opts ...grpc.CallOption) error {
    44→		ctx = withVersion(ctx)
    45→		grpcOpts, retryOpts := filterCallOptions(opts)
    46→		var p peer.Peer
    47→		grpcOpts = append(grpcOpts, grpc.Peer(&p))
    48→		callOpts := reuseOrNewWithCallOptions(intOpts, retryOpts)
    49→		// short circuit for simplicity, and avoiding allocations.
    50→		if callOpts.max == 0 {
    51→			return invoker(ctx, method, req, reply, cc, grpcOpts...)
    52→		}
    53→		var lastErr error
    54→		for attempt := uint(0); attempt < callOpts.max; attempt++ {
    55→			if err := waitRetryBackoff(ctx, attempt, callOpts); err != nil {
    56→				return err
    57→			}
    58→			c.GetLogger().Debug(
    59→				"retrying of unary invoker",
    60→				zap.String("target", cc.Target()),
    61→				zap.String("method", method),
    62→				zap.Uint("attempt", attempt),
    63→			)
    64→			lastErr = invoker(ctx, method, req, reply, cc, grpcOpts...)
    65→			if lastErr == nil {
    66→				return nil
    67→			}
    68→			c.GetLogger().Warn(
    69→				"retrying of unary invoker failed",
    70→				zap.String("target", cc.Target()),
    71→				zap.String("peer", p.String()),
    72→				zap.String("method", method),
    73→				zap.Uint("attempt", attempt),
    74→				zap.Error(lastErr),
    75→			)
    76→			if isContextError(lastErr) {
    77→				if ctx.Err() != nil {
    78→					// its the context deadline or cancellation.
    79→					return lastErr
    80→				}
    81→				// its the callCtx deadline or cancellation, in which case try again.
    82→				continue
    83→			}
    84→			if c.shouldRefreshToken(lastErr, callOpts) {
    85→				gtErr := c.refreshToken(ctx)
    86→				if gtErr != nil {
    87→					c.GetLogger().Warn(
    88→						"retrying of unary invoker failed to fetch new auth token",
    89→						zap.String("target", cc.Target()),
    90→						zap.Error(gtErr),
    91→					)
    92→					return gtErr // lastErr must be invalid auth token
    93→				}
    94→				continue
    95→			}
    96→			if !isSafeRetry(c, lastErr, callOpts) {
    97→				return lastErr
    98→			}
    99→		}
   100→		return lastErr
   101→	}
   102→}
   103→
   104→// streamClientInterceptor returns a new retrying stream client interceptor for server side streaming calls.
   105→//
   106→// The default configuration of the interceptor is to not retry *at all*. This behaviour can be
   107→// changed through options (e.g. WithMax) on creation of the interceptor or on call (through grpc.CallOptions).
   108→//
   109→// Retry logic is available *only for ServerStreams*, i.e. 1:n streams, as the internal logic needs
   110→// to buffer the messages sent by the client. If retry is enabled on any other streams (ClientStreams,
   111→// BidiStreams), the retry interceptor will fail the call.
   112→func (c *Client) streamClientInterceptor(optFuncs ...retryOption) grpc.StreamClientInterceptor {
   113→	intOpts := reuseOrNewWithCallOptions(defaultOptions, optFuncs)
   114→	return func(ctx context.Context, desc *grpc.StreamDesc, cc *grpc.ClientConn, method string, streamer grpc.Streamer, opts ...grpc.CallOption) (grpc.ClientStream, error) {
   115→		ctx = withVersion(ctx)
   116→		// getToken automatically. Otherwise, auth token may be invalid after watch reconnection because the token has expired
   117→		// (see https://github.com/etcd-io/etcd/issues/11954 for more).
   118→		err := c.getToken(ctx)
   119→		if err != nil {
   120→			c.GetLogger().Error("clientv3/retry_interceptor: getToken failed", zap.Error(err))
   121→			return nil, err
   122→		}
   123→		grpcOpts, retryOpts := filterCallOptions(opts)
   124→		callOpts := reuseOrNewWithCallOptions(intOpts, retryOpts)
   125→		// short circuit for simplicity, and avoiding allocations.
   126→		if callOpts.max == 0 {
   127→			return streamer(ctx, desc, cc, method, grpcOpts...)
   128→		}
   129→		if desc.ClientStreams {
   130→			return nil, status.Errorf(codes.Unimplemented, "clientv3/retry_interceptor: cannot retry on ClientStreams, set Disable()")
   131→		}
   132→		newStreamer, err := streamer(ctx, desc, cc, method, grpcOpts...)
   133→		if err != nil {
   134→			c.GetLogger().Error("streamer failed to create ClientStream", zap.Error(err))
   135→			return nil, err // TODO(mwitkow): Maybe dial and transport errors should be retriable?
   136→		}
   137→		retryingStreamer := &serverStreamingRetryingStream{
   138→			client:       c,
   139→			ClientStream: newStreamer,
   140→			callOpts:     callOpts,
   141→			ctx:          ctx,
   142→			streamerCall: func(ctx context.Context) (grpc.ClientStream, error) {
   143→				return streamer(ctx, desc, cc, method, grpcOpts...)
   144→			},
   145→		}
   146→		return retryingStreamer, nil
   147→	}
   148→}
