   286→func (c *Client) getToken(ctx context.Context) error {
   287→	var err error // return last error in a case of fail
   288→
   289→	if c.Token != "" {
   290→		c.authTokenBundle.UpdateAuthToken(c.Token)
   291→		return nil
   292→	}
   293→
   294→	if c.Username == "" || c.Password == "" {
   295→		return nil
   296→	}
   297→
   298→	resp, err := c.Auth.Authenticate(ctx, c.Username, c.Password)
   299→	if err != nil {
   300→		if errors.Is(err, rpctypes.ErrAuthNotEnabled) {
   301→			c.authTokenBundle.UpdateAuthToken("")
   302→			return nil
   303→		}
   304→		return err
   305→	}
   306→	c.authTokenBundle.UpdateAuthToken(resp.Token)
   307→	return nil
   308→}
