   567→func (c *Client) checkVersion() (err error) {
   568→	var wg sync.WaitGroup
   569→
   570→	eps := c.Endpoints()
   571→	errc := make(chan error, len(eps))
   572→	ctx, cancel := context.WithCancel(c.ctx)
   573→	if c.cfg.DialTimeout > 0 {
   574→		cancel()
   575→		ctx, cancel = context.WithTimeout(c.ctx, c.cfg.DialTimeout)
   576→	}
   577→
   578→	wg.Add(len(eps))
   579→	for _, ep := range eps {
   580→		// if cluster is current, any endpoint gives a recent version
   581→		go func(e string) {
   582→			defer wg.Done()
   583→			resp, rerr := c.Status(ctx, e)
   584→			if rerr != nil {
   585→				errc <- rerr
   586→				return
   587→			}
   588→			vs, serr := semver.NewVersion(resp.Version)
   589→			if serr != nil {
   590→				errc <- serr
   591→				return
   592→			}
   593→
   594→			if vs.LessThan(*minSupportedVersion()) {
   595→				rerr = ErrOldCluster
   596→			}
   597→			errc <- rerr
   598→		}(ep)
   599→	}
   600→	// wait for success
   601→	for range eps {
   602→		if err = <-errc; err != nil {
   603→			break
   604→		}
   605→	}
   606→	cancel()
   607→	wg.Wait()
   608→	return err
   609→}
