ect itself, ensuring\n// uniqueness as each context has a unique memory address.\ntype keepAliveCtxKey struct{}\n\nfunc (l *lessor) KeepAlive(ctx context.Context, id LeaseID) (<-chan *LeaseKeepAliveResponse, error) {\n\tch := make(chan *LeaseKeepAliveResponse, LeaseResponseChSize)\n\n\tl.mu.Lock()\n\t// ensure that recvKeepAliveLoop is still running\n\tselect {\n\tcase <-l.donec:\n\t\terr := l.loopErr\n\t\tl.mu.Unlock()\n\t\tclose(ch)\n\t\treturn ch, ErrKeepAliveHalted{Reason: err}\n\tdefault:\n\t}\n\tka, ok := l.keepAlives[id]\n\n\tif ctx.Done() != nil {\n\t\tctx = context.WithValue(ctx, keepAliveCtxKey{}, &ctx)\n\t}\n\tif !ok {\n\t\t// create fresh keep alive\n\t\tka = &keepAlive{\n\t\t\tchs:           []chan<- *LeaseKeepAliveResponse{ch},\n\t\t\tctxs:          []context.Context{ctx},\n\t\t\tdeadline:      time.Now().Add(l.firstKeepAliveTimeout),\n\t\t\tnextKeepAlive: time.Now(),\n\t\t\tdonec:         make(chan struct{}),\n\t\t}\n\t\tl.keepAlives[id] = ka\n\t} else {\n\t\t// add channel and context to existing keep alive\n\t\tka.ctxs = append(ka.ctxs, ctx)\n\t\tka.chs = append(ka.chs, ch)\n\t}\n\tl.mu.Unlock()\n\n\tif ctx.Done() != nil {\n\t\tgo l.keepAliveCtxCloser(ctx, id, ka.donec)\n\t}\n\tl.firstKeepAliveOnce.Do(func() {\n\t\tgo l.recvKeepAliveLoop()\n\t\tgo l.deadlineLoop()\n\t})\n\n\treturn ch, nil\n}\n\nfunc (l *lessor) KeepAliveOnce(ctx context.Context, id LeaseID) (*LeaseKeepAliveResponse, error) {\n\tfor {\n\t\tresp, err := l.keepAliveOnce(ctx, id)\n\t\tif err == nil {\n\t\t\tif resp.TTL <= 0 {\n\t\t\t\terr = rpctypes.ErrLeaseNotFound\n\t\t\t}\n\t\t\treturn resp, err\n\t\t}\n\t\tif isHaltErr(ctx, err) {\n\t\t\treturn nil, ContextError(ctx, err)\n\t\t}\n\t}\n}\n\nfunc (l *lessor) Close() error {\n\tl.stopCancel()\n\t// close for synchronous teardown if stream goroutines never launched\n\tl.firstKeepAliveOnce.Do(func() { close(l.donec) })\n\t<-l.donec\n\treturn nil\n}\n\nfunc (l *lessor) keepAliveCtxCloser(ctx context.Context, id LeaseID, donec <-chan struct{}) {\n\tselect {\n\tcase <-donec:\n\t\treturn\n\tcase <-l.donec:\n\t\treturn\n\tcase <-ctx.Done():\n\t}", "numLines": 200, "startLine": 150, "totalLines": 627}}

